{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-same-risk-input-first-ordering-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕所选泵及其相连进出口物流的缺失规格问题生成候选提案，重点限定在 feed-8、product-8 和 pump-2 上，用最小的占位式补全来回应直接诊断。",
  "answers": [
    {
      "summary": "建议先对进料流 feed-8 补充缺失的温度与流量占位规格，再对泵 pump-2 补充出口压力目标占位，最后对出料流 product-8 补充压力占位；三者风险级别相同，按输入诊断顺序排列以便审查。",
      "issues": [
        {
          "title": "feed-8 缺少必要入口规格",
          "detail": "诊断指出 Pump Suction 缺少温度和流量规格，当前仅有压力 190 kPa，导致泵入口状态不完整。",
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "product-8 缺少压力规格",
          "detail": "诊断指出 Pump Discharge 缺少压力规格，当前仅有温度 34 C，导致出口状态定义不完整。",
          "citations": [
            "diag-2",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "title": "pump-2 缺少出口压力目标",
          "detail": "诊断指出 Transfer Pump 缺少当前输送场景所需的出口压力目标参数。",
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 feed-8 增加温度与流量占位规格",
          "target": {
            "type": "stream",
            "id": "feed-8"
          },
          "rationale": "该物流被直接诊断为缺少温度和流量；采用占位而非具体数值，可在不臆造工况数据的前提下补齐求解所需输入位点。",
          "patch": {
            "spec_placeholders": {
              "temperature_c": {
                "required": true,
                "reason": "Missing per STREAM_SPEC_MISSING on feed-8"
              },
              "flow_rate": {
                "required": true,
                "reason": "Missing per STREAM_SPEC_MISSING on feed-8"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 product-8 增加压力占位规格",
          "target": {
            "type": "stream",
            "id": "product-8"
          },
          "rationale": "该出料流被直接诊断为缺少压力规格；先增加局部压力占位可使审查者明确需要补充的出口状态字段。",
          "patch": {
            "spec_placeholders": {
              "pressure_kpa": {
                "required": true,
                "reason": "Missing per STREAM_SPEC_MISSING on product-8"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 pump-2 增加出口压力目标占位参数",
          "target": {
            "type": "unit",
            "id": "pump-2"
          },
          "rationale": "泵单元被直接诊断为缺少出口压力目标；增加参数占位比直接替代现有配置更可审查，也避免在无额外证据时指定具体设定值。",
          "patch": {
            "parameter_placeholders": {
              "outlet_pressure_target_kpa": {
                "required": true,
                "reason": "Missing per UNIT_PARAMETER_INCOMPLETE on pump-2"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.94,
      "citations": [
        "diag-1",
        "diag-2",
        "diag-3",
        "flowdoc-stream-1",
        "flowdoc-stream-2",
        "flowdoc-unit-1",
        "snapshot-1"
      ]
    }
  ]
}
